import React, { useState, useEffect, useRef, useCallback, useMemo, memo } from "react";
import Footer from "components/Footers/Footer.js";
import Navbar from "components/Navbars/AuthNavbar.js";

// ==================== مودال التفاصيل - معزول تماماً ====================
// ✅ استخدام memo لمنع إعادة الإنشاء
const GroupDetailModal = memo((({ groupId, orders, onUpdateOrderStatus, onClose }) => {
  const [showIndividualOrders, setShowIndividualOrders] = useState(false);
  
  // حساب المجموعة الحالية من orders مباشرة
  const currentGroup = useMemo(() => {
    const groups = {};
    orders.forEach(order => {
      const key = `${order.name}_${order.price}`;
      if (!groups[key]) {
        groups[key] = {
          id: key,
          name: order.name,
          price: order.price,
          quantity: 0,
          orders: [],
          status: order.status
        };
      }
      groups[key].quantity++;
      groups[key].orders.push(order);
    });
    return Object.values(groups).find(g => g.id === groupId);
  }, [orders, groupId]);
  
  const handleUpdateSingleOrder = useCallback((orderId, newStatus, e) => {
    if (e) e.stopPropagation();
    onUpdateOrderStatus(orderId, newStatus);
    // ✅ لا نفعل أي شيء آخر - المودال يبقى مفتوحاً
  }, [onUpdateOrderStatus]);
  
  const handleUpdateAllOrders = useCallback((newStatus, e) => {
    if (e) e.stopPropagation();
    currentGroup?.orders.forEach(order => onUpdateOrderStatus(order.id, newStatus));
  }, [currentGroup, onUpdateOrderStatus]);
  
  if (!currentGroup) return null;
  
  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal-content-order" onClick={(e) => e.stopPropagation()} style={{ maxWidth: '500px' }}>
        <button onClick={onClose} className="close-btn">✕</button>
        <div className="text-center">
          <div className="text-5xl mb-3">📦</div>
          <h3 className="text-xl font-bold text-white mb-2">{currentGroup.name}</h3>
          <div className="order-detail-info">
