            <p><span className="detail-label">🔢 العدد الإجمالي:</span> {currentGroup.quantity}</p>
            <p><span className="detail-label">💵 السعر الإجمالي:</span> {currentGroup.price * currentGroup.quantity} دج</p>
          </div>
          
          <div className="order-detail-buttons" style={{ marginBottom: '15px', flexWrap: 'wrap' }}>
            <button onClick={(e) => handleUpdateAllOrders('completed', e)} className="btn-livre">
              ✅ Livrée (الكل)
            </button>
            <button onClick={(e) => handleUpdateAllOrders('cancelled', e)} className="btn-annule">
              ❌ Annulée (الكل)
            </button>
          </div>
          
          <button 
            onClick={() => setShowIndividualOrders(!showIndividualOrders)}
            className="btn-primary w-full mb-3"
            style={{ background: 'linear-gradient(135deg, #3b82f6, #1d4ed8)' }}
