            {showIndividualOrders ? '📋 إخفاء التفاصيل' : '🔍 عرض تفاصيل كل طلبية'}
          </button>
          
          {showIndividualOrders && (
            <div className="individual-orders-list" style={{ 
              maxHeight: '300px', 
              overflowY: 'auto', 
              marginTop: '10px',
              borderTop: '1px solid rgba(255,255,255,0.1)',
              paddingTop: '15px'
            }}>
              <h4 className="text-white font-bold mb-3 text-center">📋 الطلبات الفردية:</h4>
              {currentGroup.orders.map((order) => (
                <div 
                  key={order.id} 
                  className="individual-order-item"
                  style={{
                    background: 'rgba(255,255,255,0.05)',
                    borderRadius: '10px',
                    padding: '10px',
                    marginBottom: '10px',
                    display: 'flex',
                    justifyContent: 'space-between',
                    alignItems: 'center',
                    borderLeft: `3px solid ${order.status === 'cancelled' ? '#ef4444' : order.status === 'completed' ? '#3b82f6' : '#22c55e'}`
                  }}
                >
                  <div style={{ textAlign: 'left', flex: 1 }}>
                    <div className="text-white text-sm">🆔 طلب #{order.id}</div>
                    <div className="text-gray-400 text-xs">🕐 {order.time || 'الآن'}</div>
                    {order.notes && <div className="text-yellow-400 text-xs">📝 {order.notes}</div>}
                    <div className="text-xs mt-1">
                      <span className={`status-badge-detail ${order.status}`} style={{ fontSize: '10px', padding: '2px 6px' }}>
                        {order.status === 'pending' ? '⏳ قيد الانتظار' : order.status === 'completed' ? '✅ مكتمل' : '❌ ملغي'}
                      </span>
                    </div>
                  </div>
                  
                  <div className="individual-order-actions" style={{ display: 'flex', gap: '8px', flexWrap: 'wrap' }}>
                    <button
                      onClick={(e) => handleUpdateSingleOrder(order.id, 'completed', e)}
                      className="btn-livre"
                      style={{
                        padding: '5px 12px',
                        fontSize: '12px',
                        opacity: order.status === 'completed' ? 1 : 0.4,
                        transform: order.status === 'completed' ? 'scale(1.05)' : 'scale(1)',
                        boxShadow: order.status === 'completed' ? '0 0 8px #22c55e' : 'none',
                        transition: 'all 0.2s ease'
                      }}
                    >
                      ✅ Livrée
                    </button>
                    <button
                      onClick={(e) => handleUpdateSingleOrder(order.id, 'cancelled', e)}
                      className="btn-annule"
                      style={{
                        padding: '5px 12px',
                        fontSize: '12px',
                        opacity: order.status === 'cancelled' ? 1 : 0.4,
                        transform: order.status === 'cancelled' ? 'scale(1.05)' : 'scale(1)',
                        boxShadow: order.status === 'cancelled' ? '0 0 8px #ef4444' : 'none',
                        transition: 'all 0.2s ease'
                      }}
                    >
                      ❌ Annulée
                    </button>
                  </div>
                </div>
              ))}
            </div>
          )}
          
          <div className="mt-3 text-sm text-gray-400">
            <p>📌 {currentGroup.orders.filter(o => o.status === 'pending').length} / {currentGroup.quantity} طلبية قيد الانتظار</p>
            <p className="text-xs mt-1">💡 النافذة تبقى مفتوحة - يمكن تغيير الحالة في أي وقت</p>
          </div>
        </div>
      </div>
    </div>
  );
}));

// ==================== مكون قائمة الطلبات ====================
const OrderList = ({ orders, onUpdateOrderStatus }) => {
  const [selectedGroupId, setSelectedGroupId] = useState(null);
  const containerRef = useRef(null);
  const [showScrollButton, setShowScrollButton] = useState(false);

  const orderGroups = useMemo(() => {
    const groups = {};
    orders.forEach(order => {
      const key = `${order.name}_${order.price}`;
      if (!groups[key]) {
        groups[key] = {
          id: key,
          name: order.name,
          price: order.price,
          quantity: 0,
          orders: [],
          status: order.status
        };
      }
      groups[key].quantity++;
      groups[key].orders.push(order);
      if (order.status === 'cancelled') groups[key].status = 'cancelled';
      else if (order.status === 'completed') groups[key].status = 'completed';
      else groups[key].status = 'pending';
    });
    return Object.values(groups);
  }, [orders]);

  useEffect(() => {
    if (containerRef.current && !selectedGroupId) {
      containerRef.current.scrollTop = containerRef.current.scrollHeight;
    }
  }, [orders, selectedGroupId]);

  const handleScroll = () => {
    if (containerRef.current) {
      const { scrollTop, scrollHeight, clientHeight } = containerRef.current;
      setShowScrollButton(scrollHeight - scrollTop > clientHeight + 50);
    }
  };

  const scrollToTop = () => {
    if (containerRef.current) {
      containerRef.current.scrollTo({ top: 0, behavior: 'smooth' });
    }
  };

  return (
    <>
      <div className="order-list-container" style={{ width: '95%', maxWidth: '800px', margin: '20px auto' }}>
        <div className="order-list-header">
          <h3 className="order-list-title">
            📋 قائمة الطلبات
            <span className="order-count-badge">{orders.length}</span>
          </h3>
          <div className="header-actions">
            <button className="refresh-btn" onClick={() => window.location.reload()}>🔄</button>
          </div>
        </div>
        
        <div ref={containerRef} className="order-list-scroll" onScroll={handleScroll} style={{ maxHeight: '500px', overflowY: 'auto' }}>
          {orderGroups.length === 0 ? (
            <div className="empty-orders">
              <div className="empty-icon">🍽️</div>
              <p>لا توجد طلبات حالياً</p>
            </div>
          ) : (
            orderGroups.map((group) => (
              <div key={group.id} className={`order-item ${group.status} animate-slide-up`}>
                <div className="order-item-content">
                  <div 
                    className="order-info" 
                    onClick={() => setSelectedGroupId(selectedGroupId === group.id ? null : group.id)} 
                    style={{ cursor: 'pointer', flex: 1 }}
                  >
                    <span className="order-icon">🍽️</span>
                    <div className="order-details">
                      <div className="order-name">{group.name}</div>
                      <div className="order-meta">
                        <span className="order-price">{group.price} دج</span>
                        {group.quantity > 1 && <span className="order-quantity-badge">×{group.quantity}</span>}
                      </div>
                    </div>
                  </div>
                  <div className="order-actions">
                    <div className={`order-status ${group.status}`}>
                      {group.status === 'pending' ? '⏳' : group.status === 'completed' ? '✅' : '❌'}
                    </div>
                  </div>
                </div>
              </div>
            ))
          )}
        </div>
        
        {showScrollButton && <button className="scroll-to-top" onClick={scrollToTop}>↑</button>}
      </div>
      
      {/* ✅ المودال يستقبل orders كـ prop وليس group object */}
      {selectedGroupId && (
        <GroupDetailModal 
          groupId={selectedGroupId}
          orders={orders}
          onUpdateOrderStatus={onUpdateOrderStatus}
          onClose={() => setSelectedGroupId(null)} 
        />
      )}
    </>
  );
};

// ==================== مكون تعديل CV ====================
const EditCVModal = ({ workerInfo, onSave, onClose }) => {
  const [editedInfo, setEditedInfo] = useState({ ...workerInfo });
  const [newSkill, setNewSkill] = useState("");

  const addSkill = () => {
    if (newSkill.trim() && !editedInfo.skills.includes(newSkill.trim())) {
      setEditedInfo({ ...editedInfo, skills: [...editedInfo.skills, newSkill.trim()] });
      setNewSkill("");
    }
  };

  const removeSkill = (skillToRemove) => {
    setEditedInfo({ ...editedInfo, skills: editedInfo.skills.filter(skill => skill !== skillToRemove) });
  };

  const handleSave = () => {
    onSave(editedInfo);
    onClose();
  };

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal-content" onClick={(e) => e.stopPropagation()} style={{ maxWidth: '600px' }}>
        <button onClick={onClose} className="close-btn">✕</button>
        <div className="text-center">
          <div className="text-5xl mb-4">✏️</div>
          <h2 className="text-2xl font-bold text-white mb-4">تعديل السيرة الذاتية</h2>
        </div>
        
        <div className="edit-cv-form">
          <div className="mb-4">
            <label className="text-white text-sm block mb-2">👤 الاسم الكامل</label>
            <input type="text" className="w-full p-3 rounded-xl bg-white/10 text-white border border-green-500/30" value={editedInfo.name} onChange={(e) => setEditedInfo({...editedInfo, name: e.target.value})} />
          </div>
          
          <div className="mb-4">
            <label className="text-white text-sm block mb-2">💼 المسمى الوظيفي</label>
            <input type="text" className="w-full p-3 rounded-xl bg-white/10 text-white border border-green-500/30" value={editedInfo.role} onChange={(e) => setEditedInfo({...editedInfo, role: e.target.value})} />
          </div>
          
          <div className="mb-4">
            <label className="text-white text-sm block mb-2">📧 البريد الإلكتروني</label>
            <input type="email" className="w-full p-3 rounded-xl bg-white/10 text-white border border-green-500/30" value={editedInfo.email} onChange={(e) => setEditedInfo({...editedInfo, email: e.target.value})} />
          </div>
          
          <div className="mb-4">
            <label className="text-white text-sm block mb-2">📱 رقم الهاتف</label>
            <input type="tel" className="w-full p-3 rounded-xl bg-white/10 text-white border border-green-500/30" value={editedInfo.phone} onChange={(e) => setEditedInfo({...editedInfo, phone: e.target.value})} />
          </div>
          
          <div className="mb-4">
            <label className="text-white text-sm block mb-2">📍 الموقع</label>
            <input type="text" className="w-full p-3 rounded-xl bg-white/10 text-white border border-green-500/30" value={editedInfo.location} onChange={(e) => setEditedInfo({...editedInfo, location: e.target.value})} />
          </div>
          
          <div className="mb-4">
            <label className="text-white text-sm block mb-2">📝 السيرة الذاتية (Bio)</label>
            <textarea className="w-full p-3 rounded-xl bg-white/10 text-white border border-green-500/30" rows="3" value={editedInfo.bio} onChange={(e) => setEditedInfo({...editedInfo, bio: e.target.value})} />
          </div>
          
          <div className="mb-4">
            <label className="text-white text-sm block mb-2">💪 المهارات</label>
            <div className="flex flex-wrap gap-2 mb-2">
              {editedInfo.skills.map((skill, i) => (
                <span key={i} className="skill-tag" style={{ display: 'inline-flex', alignItems: 'center', gap: '5px' }}>
                  {skill}
                  <button onClick={() => removeSkill(skill)} style={{ background: 'none', border: 'none', color: '#ef4444', cursor: 'pointer', fontSize: '14px' }}>✕</button>
                </span>
              ))}
            </div>
            <div className="flex gap-2">
              <input type="text" className="flex-1 p-2 rounded-xl bg-white/10 text-white border border-green-500/30" placeholder="أضف مهارة جديدة" value={newSkill} onChange={(e) => setNewSkill(e.target.value)} onKeyPress={(e) => e.key === 'Enter' && addSkill()} />
              <button onClick={addSkill} className="btn-primary">+ إضافة</button>
            </div>
          </div>
          
          <button onClick={handleSave} className="btn-primary w-full mt-4">💾 حفظ التغييرات</button>
        </div>
      </div>
    </div>
  );
};

